// 일일 리포트 이메일 HTML 생성
const summaryData = $input.item.json;
const coinsData = summaryData.coins || [];
const summary = summaryData.summary || '시장 요약을 불러올 수 없습니다.';

const now = new Date().toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' });
const today = new Date().toLocaleDateString('ko-KR', { timeZone: 'Asia/Seoul', year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' });

// 상승/하락 코인 분류
const rising = coinsData.filter(c => parseFloat(c.change_24h) > 0);
const falling = coinsData.filter(c => parseFloat(c.change_24h) <= 0);

// 코인 행 생성
const coinRows = coinsData.map(coin => {
  const change = parseFloat(coin.change_24h);
  const color = change >= 0 ? '#3fb950' : '#f85149';
  const arrow = change >= 0 ? '▲' : '▼';
  const volume = (parseFloat(coin.volume_24h) / 1e6).toFixed(1);
  return `
    <tr style="border-bottom: 1px solid #21262d;">
      <td style="padding: 12px 8px; font-weight: 700; color: #e6edf3;">${coin.symbol.replace('USDT', '')}</td>
      <td style="padding: 12px 8px; color: #e6edf3;">${coin.name}</td>
      <td style="padding: 12px 8px; text-align: right; font-weight: 700; color: #e6edf3;">$${parseFloat(coin.price).toLocaleString('en-US', {minimumFractionDigits: 2})}</td>
      <td style="padding: 12px 8px; text-align: right; color: ${color}; font-weight: 600;">${arrow} ${Math.abs(change).toFixed(2)}%</td>
      <td style="padding: 12px 8px; text-align: right; color: #8b949e;">$${volume}M</td>
    </tr>`;
}).join('');

const htmlBody = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: 'Helvetica Neue', Arial, sans-serif; background: #0d1117; color: #e6edf3; margin: 0; padding: 0; }
    .container { max-width: 640px; margin: 40px auto; padding: 0 20px; }
    .header { background: linear-gradient(135deg, #161b22, #1c2128); padding: 30px; border-radius: 12px 12px 0 0; border-bottom: 2px solid #58a6ff; }
    .header h1 { margin: 0; font-size: 22px; color: #58a6ff; }
    .header p { margin: 8px 0 0; color: #8b949e; }
    .body { background: #161b22; padding: 30px; border-radius: 0 0 12px 12px; }
    .stats-grid { display: flex; gap: 16px; margin: 20px 0; }
    .stat-box { flex: 1; background: #0d1117; border: 1px solid #30363d; border-radius: 8px; padding: 16px; text-align: center; }
    .stat-value { font-size: 28px; font-weight: 700; }
    .stat-label { color: #8b949e; font-size: 12px; margin-top: 4px; }
    .ai-box { background: #0d1117; border: 1px solid #388bfd33; border-radius: 8px; padding: 16px; margin: 20px 0; }
    .ai-box h3 { color: #58a6ff; font-size: 14px; margin: 0 0 10px; }
    .ai-box p { color: #cdd9e5; font-size: 14px; line-height: 1.7; margin: 0; }
    table { width: 100%; border-collapse: collapse; margin: 20px 0; }
    thead { background: #21262d; }
    thead th { padding: 10px 8px; text-align: left; color: #8b949e; font-size: 12px; text-transform: uppercase; letter-spacing: 0.5px; }
    .footer { text-align: center; margin-top: 30px; color: #484f58; font-size: 12px; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>📊 일일 암호화폐 시장 리포트</h1>
      <p>${today} | ${now} 기준</p>
    </div>
    <div class="body">
      <div class="stats-grid">
        <div class="stat-box">
          <div class="stat-value" style="color: #3fb950;">${rising.length}</div>
          <div class="stat-label">상승 코인</div>
        </div>
        <div class="stat-box">
          <div class="stat-value" style="color: #f85149;">${falling.length}</div>
          <div class="stat-label">하락 코인</div>
        </div>
        <div class="stat-box">
          <div class="stat-value" style="color: #58a6ff;">${coinsData.length}</div>
          <div class="stat-label">모니터링</div>
        </div>
      </div>

      <div class="ai-box">
        <h3>🤖 EXAONE 3.5 AI 시장 분석</h3>
        <p>${summary}</p>
      </div>

      <h3 style="color: #e6edf3; font-size: 16px; margin: 24px 0 12px;">코인별 현황</h3>
      <table>
        <thead>
          <tr>
            <th>심볼</th>
            <th>이름</th>
            <th style="text-align:right;">현재가</th>
            <th style="text-align:right;">24h 변동</th>
            <th style="text-align:right;">거래량</th>
          </tr>
        </thead>
        <tbody>${coinRows}</tbody>
      </table>
    </div>
    <div class="footer">
      Crypto Monitor | Django + Celery + EXAONE 3.5 (Ollama)<br>
      <a href="http://localhost:3000" style="color: #58a6ff;">Grafana 대시보드 보기</a>
    </div>
  </div>
</body>
</html>`;

return [{
  json: {
    html_body: htmlBody,
    subject: `[Crypto Monitor] ${today} 일일 시장 리포트`,
    coins_count: coinsData.length,
    rising_count: rising.length,
    falling_count: falling.length,
  }
}];
